      "wurtz@google.com": { name: "David Wurtz", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjW7KVh0yVuDb5C5TdRwGD7YYrY9iwTZzjNklnwKjpKGKeTFhayw=s64" },
      "cdcarroll@google.com": { name: "Chris Carroll", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjVbB5SNQqui8-Dhh4ttI-p8lTdndJGcwTKlRrPnnNuKpJEXlKqF=s64" },
      "jannicar@google.com": { name: "Jannica Robertson", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWDycqL54QiGjUColQXjRQ80GsUFizqLOjmWN5j5IAy9-NLFIO=s64" },
      "ftj@google.com": { name: "Frank Tisellano", avatar: "https://lh3.googleusercontent.com/a-/ALV-UjWIXtfhCFx8S8zhFpLAaF9NZSiDJZmtDjpzW8DRqDnltb-otP9-=s64" },
