    };

    async function loadSyncedState() {
      if (!envId) {
        renderBoard();
        return;
      }
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && Array.isArray(json.data)) {
          tasks = json.data;
          renderBoard();
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    async function saveSyncedState(newState) {
      if (!envId) return;
      try {
        await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
      } catch (err) {
        console.error("Failed to save synced state:", err);
      }
    }

    function renderBoard() {
      const columns = {
        "To Do": document.getElementById("col-todo"),
        "In Progress": document.getElementById("col-inprogress"),
        "Done": document.getElementById("col-done")
      };

      Object.values(columns).forEach(col => col.innerHTML = '');

      tasks.forEach(task => {
        if (!task.source || !task.source.toLowerCase().includes("email")) return;

        const card = document.createElement("div");
        card.className = "bg-white p-3.5 rounded-lg border border-gray-200 hover:border-[#0b57d0] transition duration-150 flex flex-col gap-2 relative group";

        card.innerHTML = `
          <div class="text-[13px] font-normal text-gray-800 leading-normal font-sans">${escapeHTML(task.title)}</div>
          <div class="flex items-center justify-between mt-1">
            <div class="flex items-center gap-1.5">
              <img src="${task.assignee.avatar}" class="w-5 h-5 rounded-full object-cover border border-gray-100" alt="${escapeHTML(task.assignee.name)}">
              <span class="text-[11px] text-gray-600 font-medium">${escapeHTML(task.assignee.name)}</span>
            </div>
            <div class="text-[10px] text-gray-400 truncate max-w-[120px]" title="${escapeHTML(task.source)}">
              📧 ${escapeHTML(task.source.replace(/^Email from /i, ''))}
            </div>
          </div>

          <div class="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition duration-150 flex items-center gap-1 bg-white pl-1.5 rounded">
            ${task.status !== 'To Do' ? `<button onclick="moveTask('${task.id}', 'prev')" class="text-[10px] p-1 text-gray-400 hover:text-[#0b57d0] bg-gray-50 rounded" title="Move back">←</button>` : ''}
            ${task.status !== 'Done' ? `<button onclick="moveTask('${task.id}', 'next')" class="text-[10px] p-1 text-gray-400 hover:text-[#0b57d0] bg-gray-50 rounded" title="Move forward">→</button>` : ''}
            <button onclick="deleteTask('${task.id}')" class="text-[10px] p-1 text-gray-400 hover:text-red-500 bg-gray-50 rounded" title="Delete">✕</button>
          </div>
        `;

        if (columns[task.status]) {
          columns[task.status].appendChild(card);
        }
      });
    }

    function moveTask(taskId, direction) {
      const statusFlow = ["To Do", "In Progress", "Done"];
      const task = tasks.find(t => t.id === taskId);
      if (!task) return;

      const currentIndex = statusFlow.indexOf(task.status);
      let nextIndex = currentIndex;

      if (direction === 'next' && currentIndex < statusFlow.length - 1) {
        nextIndex++;
      } else if (direction === 'prev' && currentIndex > 0) {
        nextIndex--;
      }

      task.status = statusFlow[nextIndex];
      renderBoard();
      saveSyncedState(tasks);
    }

    function deleteTask(taskId) {
      tasks = tasks.filter(t => t.id !== taskId);
      renderBoard();
      saveSyncedState(tasks);
    }

    function addTask() {
      const titleInput = document.getElementById("task-title-input");
      const assigneeSelect = document.getElementById("task-assignee-select");
      const title = titleInput.value.trim();
      const email = assigneeSelect.value;

      if (!title) return;

      const member = teamMembers[email];
      const newTask = {
        id: "task-" + Date.now(),
        title: title,
        source: `Email from ${member.name} (${email})`,
        assignee: {
          name: member.name,
          email: email,
          avatar: member.avatar
        },
        status: "To Do"
      };

      tasks.unshift(newTask);
      titleInput.value = '';
      renderBoard();
      saveSyncedState(tasks);
    }

    function escapeHTML(str) {
      return str.replace(/[&<>'"]/g, 
        tag => ({
          '&': '&amp;',
          '<': '&lt;',
          '>': '&gt;',
          "'": '&#39;',
          '"': '&quot;'
        }[tag] || tag)
      );
    }

    if (envId) {
      loadSyncedState();
      setInterval(loadSyncedState, 2000);
    } else {
      renderBoard();
    }
  </script>
</body>
</html>
